              initial={{ opacity: 0.1 }} animate={{ opacity: [0.08, 0.55, 0.08] }}
              transition={{ duration: 2.5 + (k % 4), delay: (k % 6) * 0.25, repeat: Infinity }} />
            <motion.circle cx={n.x} cy={n.y} r={2.5}
              fill={k % 3 === 0 ? "rgba(199,210,254,0.95)" : "rgba(186,230,253,0.95)"}
              animate={{ r: [2, 3.8, 2] }}
              transition={{ duration: 2 + (k % 3), delay: (k % 5) * 0.3, repeat: Infinity }} />
          </g>
        ))}
      </svg>
      <div className="absolute inset-x-0 bottom-0 h-32 bg-gradient-to-t from-background to-transparent" />
    </div>
  );
}

/* ── Floating tech icons scatter ─────────────────────────── */
function TechIconsScatter() {
  const ICONS: React.ElementType[] = [Code2, Cpu, Cloud, Terminal, Brain, Sparkles, GitBranch, MonitorSmartphone, Workflow, Bug, Layers, Zap, Smartphone, ShieldCheck, Activity, Cog, Boxes, Database, Server, Lock, Network, Binary, Fingerprint];
  const items = useMemo(() => {
    const cols = 7; const rows = 10;
    return Array.from({ length: rows * cols }).map((_, idx) => {
      const seed = (idx + 1) * 9301 + 49297;
      if (seed % 9 < 2) return null;
      const c = idx % cols; const r = Math.floor(idx / cols);
      const xJ = (((seed >> 7) % 100) - 50) / 100; const yJ = (((seed >> 11) % 100) - 50) / 100;
      return {
        Icon: ICONS[(seed >> 5) % ICONS.length],
        x: ((c + 0.5 + xJ * 0.7) / cols) * 100,
        y: ((r + 0.5 + yJ * 0.7) / rows) * 100,
        size: 16 + ((seed >> 13) % 20), rot: ((seed >> 9) % 50) - 25,
        delay: ((seed >> 17) % 100) / 20, dur: 7 + ((seed >> 15) % 8), floatY: 4 + ((seed >> 19) % 8),
      };
    }).filter(Boolean) as NonNullable<ReturnType<typeof Array.from<null>>>[];
  }, []);

  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none" aria-hidden>
      {items.map((it: any, i) => {
        const Icon = it.Icon;
        return (
          <motion.div key={i} className="absolute text-primary/[0.07] dark:text-primary/[0.10]"
            style={{ left: `${it.x}%`, top: `${it.y}%` }}
            initial={{ rotate: it.rot, opacity: 0.04 }}
            animate={{ y: [-it.floatY, it.floatY, -it.floatY], rotate: [it.rot - 5, it.rot + 5, it.rot - 5], opacity: [0.05, 0.13, 0.05] }}
            transition={{ duration: it.dur, delay: it.delay, repeat: Infinity, ease: "easeInOut" }}>
            <Icon size={it.size} strokeWidth={1.5} />
          </motion.div>
        );
      })}
    </div>
  );
}

